var minimumSwaps = function(nums) {
    const n = nums.length;
    let z = 0;
    for (const v of nums) if (v === 0) z++;
    const front = n - z;
    let count = 0;
    for (let i = 0; i < front; i++) if (nums[i] === 0) count++;
    return count;
};
